items.css:
@keyframes spinner-ball {
  0% {
    transform: translateX(0) scale(1);
  }
  25% {
    transform: translateX(calc(var(--spinner-size, 40px) / 2)) scale(0.25);
  }
  50% {
    transform: translateX(0) scale(1);
  }
  75% {
    transform: translateX(calc(var(--spinner-size, 40px) / -2)) scale(0.25);
  }
  100% {
    transform: translateX(0) scale(1);
  }
}

@keyframes spinner-grid {
  0% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
  }
  50% {
    width: calc(var(--spinner-size, 40px) / 4);
    height: calc(var(--spinner-size, 40px) / 4);
    top: calc(var(--spinner-size, 40px) / 2 - var(--spinner-size, 40px) / 8);
    left: calc(var(--spinner-size, 40px) / 2 - var(--spinner-size, 40px) / 8);
  }
  100% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
  }
}

@keyframes spinner-swap {
  0% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
  }
  50% {
    top: var(--spinner-swap-mid-y, 0px);
    left: var(--spinner-swap-mid-x, 0px);
  }
  100% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
  }
}

@keyframes spinner-bars {
  0% {
    width: calc(var(--spinner-size, 40px) / 20);
  }
  50% {
    width: calc(var(--spinner-size, 40px) / 6);
  }
  100% {
    width: calc(var(--spinner-size, 40px) / 20);
  }
}

@keyframes spinner-wave {
  25% {
    transform: skewY(25deg);
  }
  50% {
    height: 100%;
    margin-top: 0;
  }
  75% {
    transform: skewY(-25deg);
  }
}

@keyframes spinner-push {
  15% {
    transform: scaleY(1) translateX(calc(10 * var(--spinner-size-unit, 1px)));
  }
  90% {
    transform: scaleY(0.05) translateX(calc(-5 * var(--spinner-size-unit, 1px)));
  }
  100% {
    transform: scaleY(0.05) translateX(calc(-5 * var(--spinner-size-unit, 1px)));
  }
}

@keyframes spinner-firework {
  0% {
    opacity: 1;
    transform: scale(0.1);
  }
  25% {
    opacity: 0.85;
  }
  100% {
    transform: scale(1);
    opacity: 0;
  }
}

@keyframes spinner-stage {
  0% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
  }
  25% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
    opacity: 0;
  }
  50% {
    top: calc(var(--spinner-y, 0px) + var(--spinner-size, 40px) / 2);
    left: var(--spinner-x, 0px);
    opacity: 0;
  }
  100% {
    top: var(--spinner-y, 0px);
    left: var(--spinner-x, 0px);
    opacity: 1;
  }
}

@keyframes spinner-heart {
  0% {
    transform: scale(1);
  }
  25% {
    transform: scale(0.75);
  }
  50% {
    transform: scale(1);
  }
  65% {
    transform: scale(1);
  }
  80% {
    transform: scale(0.75);
  }
  100% {
    transform: scale(1);
  }
}

@keyframes spinner-guard {
  0% {
    transform: rotateY(90deg);
  }
  50% {
    transform: rotateY(0deg);
  }
  100% {
    transform: rotateY(90deg);
  }
}

@keyframes spinner-circle {
  0% {
    transform: rotate(0);
  }
  100% {
    transform: rotate(360deg);
  }
}

@keyframes spinner-spiral {
  0% {
    transform: rotateX(0deg);
  }
  25% {
    transform: rotateX(-90deg);
  }
  50% {
    transform: rotateX(-180deg);
  }
  75% {
    transform: rotateX(-270deg);
  }
  100% {
    transform: rotateX(-360deg);
  }
}

@keyframes spinner-pulse {
  0% {
    opacity: 1;
  }
  50% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}

@keyframes spinner-sequence {
  0% {
    top: var(--spinner-size, 40px);
    transform: rotateY(0deg);
  }
  30% {
    top: 0;
    transform: rotateY(90deg);
  }
  100% {
    transform: rotateY(0deg);
    top: calc(var(--spinner-size, 40px) * -1);
  }
}

@keyframes spinner-domino {
  0% {
    transform: translateX(var(--spinner-domino-t0, 0px)) rotate(0deg);
    opacity: 0;
  }
  14.28% {
    transform: translateX(var(--spinner-domino-t1, 0px)) rotate(0deg);
    opacity: 1;
  }
  28.56% {
    transform: translateX(var(--spinner-domino-t2, 0px)) rotate(0deg);
    opacity: 1;
  }
  37.12% {
    transform: translateX(var(--spinner-domino-t3, 0px)) rotate(0deg);
    opacity: 1;
  }
  42.84% {
    transform: translateX(var(--spinner-domino-t4, 0px)) rotate(10deg);
    opacity: 1;
  }
  57.12% {
    transform: translateX(var(--spinner-domino-t5, 0px)) rotate(40deg);
    opacity: 1;
  }
  71.4% {
    transform: translateX(var(--spinner-domino-t6, 0px)) rotate(62deg);
    opacity: 1;
  }
  85.68% {
    transform: translateX(var(--spinner-domino-t7, 0px)) rotate(72deg);
    opacity: 1;
  }
  100% {
    transform: translateX(var(--spinner-domino-t8, 0px)) rotate(74deg);
    opacity: 0;
  }
}

@keyframes spinner-impulse {
  0% {
    background: var(--spinner-back-color, currentColor);
    transform: scale(1);
    animation-timing-function: cubic-bezier(1, 0, 0.7, 1);
  }
  40% {
    background: var(--spinner-front-color, currentColor);
    transform: scale(1.5);
    animation-timing-function: cubic-bezier(0.3, 0, 0, 1);
  }
  72.5% {
    background: var(--spinner-back-color, currentColor);
    transform: scale(1);
    animation-timing-function: linear;
  }
  100% {
    background: var(--spinner-back-color, currentColor);
    transform: scale(1);
  }
}

@keyframes spinner-cube {
  from {
    transform: rotateX(0) rotateY(0);
  }
  to {
    transform: rotateX(360deg) rotateY(360deg);
  }
}

@keyframes spinner-fill-rotate {
  0% {
    transform: rotate(0deg);
  }
  25% {
    transform: rotate(180deg);
  }
  50% {
    transform: rotate(180deg);
  }
  75% {
    transform: rotate(360deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

@keyframes spinner-fill {
  0% {
    height: 0%;
  }
  25% {
    height: 0%;
  }
  50% {
    height: 100%;
  }
  75% {
    height: 100%;
  }
  100% {
    height: 0%;
  }
}

@keyframes spinner-sphere-rotate {
  to {
    transform: rotate(360deg);
  }
}

@keyframes spinner-sphere {
  0% {
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(1);
  }
  5% {
    transform: translateX(calc(var(--spinner-size, 30px) / -12)) translateY(calc(var(--spinner-size, 30px) / -12)) scale(0);
  }
  50% {
    transform: translateX(calc(var(--spinner-size, 30px) / -12)) translateY(calc(var(--spinner-size, 30px) / -12)) scale(0);
  }
  55% {
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(1);
  }
}

@keyframes spinner-flag {
  0% {
    transform: translateY(0);
    opacity: 1;
  }
  50% {
    transform: translateY(calc(var(--spinner-size, 40px) / -5));
    opacity: 0.25;
  }
  100% {
    transform: translateY(0);
    opacity: 1;
  }
}

@keyframes spinner-clap-rotate {
  50% {
    transform: rotate(180deg) scale(1.125);
  }
  100% {
    transform: rotate(360deg);
  }
}

@keyframes spinner-clap {
  0% {
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(1.25);
  }
  5% {
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(1.75);
  }
  50% {
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(0.25);
  }
  55% {
    background-color: var(--spinner-back-color, currentColor);
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(1);
  }
}

@keyframes spinner-rotate {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(1440deg);
    opacity: 0.05;
  }
}

@keyframes spinner-swish {
  50% {
    transform: scale(0);
    background-color: var(--spinner-back-color, currentColor);
  }
}

@keyframes spinner-goo-rotate {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

@keyframes spinner-goo {
  0% {
    transform: translateY(0) scale(1);
  }
  50% {
    transform: translateY(var(--spinner-translate-to, 0px)) scale(0.8);
  }
  100% {
    transform: translateY(0) scale(1);
  }
}

@keyframes spinner-comb {
  to {
    transform: rotate(450deg);
  }
}

@keyframes spinner-pong-player {
  0% {
    top: var(--spinner-pong-player-top-a, 0px);
  }
  50% {
    top: var(--spinner-pong-player-top-b, 0px);
  }
  100% {
    top: var(--spinner-pong-player-top-a, 0px);
  }
}

@keyframes spinner-pong-ball {
  0% {
    top: calc(var(--spinner-size, 60px) / 3.5 - var(--spinner-size, 60px) / 8);
    left: calc(var(--spinner-size, 60px) / 12);
  }
  25% {
    top: calc(var(--spinner-size, 60px) / 3.5);
    left: calc(var(--spinner-size, 60px) - var(--spinner-size, 60px) / 8);
  }
  50% {
    top: calc(var(--spinner-size, 60px) / 1.75 - var(--spinner-size, 60px) / 8);
    left: calc(var(--spinner-size, 60px) / 12);
  }
  75% {
    top: calc(var(--spinner-size, 60px) / 3.5);
    left: calc(var(--spinner-size, 60px) - var(--spinner-size, 60px) / 8);
  }
  100% {
    top: calc(var(--spinner-size, 60px) / 3.5 - var(--spinner-size, 60px) / 8);
    left: calc(var(--spinner-size, 60px) / 12);
  }
}

@keyframes spinner-rainbow {
  0% {
    border-width: calc(10 * var(--spinner-size-unit, 1px));
  }
  25% {
    border-width: calc(3 * var(--spinner-size-unit, 1px));
  }
  50% {
    transform: rotate(115deg);
    border-width: calc(10 * var(--spinner-size-unit, 1px));
  }
  75% {
    border-width: calc(3 * var(--spinner-size-unit, 1px));
  }
  100% {
    border-width: calc(10 * var(--spinner-size-unit, 1px));
  }
}

@keyframes spinner-ring-first {
  0% {
    box-shadow: inset 0 0 0 calc(var(--spinner-size, 30px) / 10) var(--spinner-color, currentColor);
    opacity: 1;
  }
  50%,
  100% {
    box-shadow: inset 0 0 0 0 var(--spinner-color, currentColor);
    opacity: 0;
  }
}

@keyframes spinner-ring-second {
  0%,
  50% {
    box-shadow: inset 0 0 0 0 var(--spinner-color, currentColor);
    opacity: 0;
  }
  100% {
    box-shadow: inset 0 0 0 calc(var(--spinner-size, 30px) / 10) var(--spinner-color, currentColor);
    opacity: 1;
  }
}

@keyframes spinner-hoop {
  0% {
    opacity: 0;
    border-color: var(--spinner-color, currentColor);
    transform: rotateX(65deg) rotateY(45deg) translateZ(calc(var(--spinner-size, 45px) * -1.5)) scale(0.1);
  }
  40% {
    opacity: 1;
    transform: rotateX(0deg) rotateY(20deg) translateZ(0) scale(1);
  }
  100% {
    opacity: 0;
    transform: rotateX(65deg) rotateY(-45deg) translateZ(calc(var(--spinner-size, 45px) * -1.5)) scale(0.1);
  }
}

@keyframes spinner-flapper {
  100% {
    opacity: 0;
    transform: translateX(var(--spinner-x, 0px)) translateY(var(--spinner-y, 0px)) scale(1);
  }
}

@keyframes spinner-magic {
  100% {
    transform: translateX(-50%) translateY(-50%) rotate(360deg);
  }
}

@keyframes spinner-jellyfish {
  0% {
    transform: translateY(calc(var(--spinner-size, 60px) / -5));
  }
  50% {
    transform: translateY(calc(var(--spinner-size, 60px) / 4));
  }
  100% {
    transform: translateY(calc(var(--spinner-size, 60px) / -5));
  }
}

@keyframes spinner-trace {
  0% {
    border: calc(var(--spinner-size, 35px) / 10) solid var(--spinner-back-color, currentColor);
  }
  25% {
    border: calc(var(--spinner-size, 35px) / 10) solid var(--spinner-front-color, currentColor);
  }
  50% {
    border: calc(var(--spinner-size, 35px) / 10) solid var(--spinner-back-color, currentColor);
  }
  100% {
    border: calc(var(--spinner-size, 35px) / 10) solid var(--spinner-back-color, currentColor);
  }
}

@keyframes spinner-trace-move {
  25% {
    transform: translate(calc(var(--spinner-size, 35px) / 2 + var(--spinner-size, 35px) / 10), 0);
  }
  50% {
    transform: translate(
      calc(var(--spinner-size, 35px) / 2 + var(--spinner-size, 35px) / 10),
      calc(var(--spinner-size, 35px) / 2 + var(--spinner-size, 35px) / 10)
    );
  }
  75% {
    transform: translate(0, calc(var(--spinner-size, 35px) / 2 + var(--spinner-size, 35px) / 10));
  }
  100% {
    transform: translate(0, 0);
  }
}

@keyframes spinner-classic {
  0% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}

@keyframes spinner-whisper {
  0% {
    transform: scale(1, 1);
    opacity: 1;
    background-color: var(--spinner-back-color, currentColor);
  }
  100% {
    transform: scale(0, 0);
    opacity: 0;
    background-color: var(--spinner-front-color, currentColor);
  }
}

@keyframes spinner-whisper-spin {
  0% {
    transform: rotate(0deg);
  }
  25% {
    transform: rotate(90deg);
  }
  50% {
    transform: rotate(180deg);
  }
  75% {
    transform: rotate(270deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

@keyframes spinner-metro-rotate {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(-360deg);
  }
}

@keyframes spinner-metro-ball {
  0% {
    opacity: 0;
  }
  100% {
    opacity: 1;
  }
}

.spinner-delay-0 {
  animation-delay: 0s;
}

.spinner-delay-1 {
  animation-delay: 0.05s;
}

.spinner-delay-2 {
  animation-delay: 0.1s;
}

.spinner-delay-3 {
  animation-delay: 0.15s;
}

.spinner-delay-4 {
  animation-delay: 0.2s;
}

@media (prefers-reduced-motion: reduce) {
  [role="status"] * {
    animation-duration: 0s !important;
    animation-play-state: paused !important;
  }
}
